import{_ as a,o as i,c as l,ak as s}from"./chunks/framework.BQh-lcRV.js";const g=JSON.parse('{"title":"提交规范","description":"","frontmatter":{},"headers":[],"relativePath":"guide/git/commit.md","filePath":"guide/git/commit.md","lastUpdated":1775392610000}'),t={name:"guide/git/commit.md"};function o(d,e,c,n,p,r){return i(),l("div",null,[...e[0]||(e[0]=[s(`<h1 id="提交规范" tabindex="-1">提交规范 <a class="header-anchor" href="#提交规范" aria-label="Permalink to “提交规范”">​</a></h1><p>推荐使用 Conventional Commits 风格编写提交信息。</p><p>基础格式如下：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&lt;type&gt;(&lt;scope&gt;): &lt;subject&gt;</span></span></code></pre></div><ul><li><code>Header</code>：必填</li><li><code>Body</code>：可选</li><li><code>Footer</code>：可选</li></ul><h2 id="header" tabindex="-1">Header <a class="header-anchor" href="#header" aria-label="Permalink to “Header”">​</a></h2><p><code>Header</code> 只有一行，包含 <code>type</code>、<code>scope</code> 和 <code>subject</code> 三部分。</p><ul><li><code>type</code>：必填</li><li><code>scope</code>：可选</li><li><code>subject</code>：必填</li></ul><p>例如：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>feat(auth): add login by sms</span></span>
<span class="line"><span>fix(api): handle empty response</span></span>
<span class="line"><span>docs(git): update commit guide</span></span></code></pre></div><h3 id="type" tabindex="-1">type <a class="header-anchor" href="#type" aria-label="Permalink to “type”">​</a></h3><p><code>type</code> 用于说明本次提交的类别，常用值如下：</p><ul><li><code>feat</code>：新功能</li><li><code>fix</code>：修复 bug</li><li><code>docs</code>：文档变更</li><li><code>style</code>：代码格式调整，不影响运行结果</li><li><code>refactor</code>：重构，既不是新功能也不是修复 bug</li><li><code>test</code>：测试相关变更</li><li><code>chore</code>：构建、依赖、脚手架或辅助工具变更</li></ul><p>一般来说，<code>feat</code> 和 <code>fix</code> 更适合进入 Change log；其他类型是否进入可按项目需要决定。</p><h3 id="scope" tabindex="-1">scope <a class="header-anchor" href="#scope" aria-label="Permalink to “scope”">​</a></h3><p><code>scope</code> 用于说明影响范围，比如模块名、页面名或功能名。</p><p>建议：</p><ul><li>尽量简短，能看出改动范围即可</li><li>优先使用模块名、目录名、页面名、功能名</li><li>如果这次提交影响范围很散，也可以省略</li></ul><p>示例：</p><ul><li><code>auth</code></li><li><code>api</code></li><li><code>git</code></li><li><code>docs</code></li></ul><h3 id="subject" tabindex="-1">subject <a class="header-anchor" href="#subject" aria-label="Permalink to “subject”">​</a></h3><p><code>subject</code> 是对本次提交目的的简短描述，建议控制在 50 个字符以内。</p><ul><li>使用动词开头，直接描述本次提交做了什么</li><li>建议使用小写开头</li><li>结尾不要加句号</li><li>尽量写清“目的”，不要只写“修改代码”“更新内容”这类空话</li></ul><p>示例：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>feat(user): add profile page</span></span>
<span class="line"><span>fix(order): prevent duplicate submit</span></span>
<span class="line"><span>docs(git): update commit guide</span></span></code></pre></div><h2 id="body" tabindex="-1">Body <a class="header-anchor" href="#body" aria-label="Permalink to “Body”">​</a></h2><p><code>Body</code> 用于补充说明提交背景、实现思路或影响范围。</p><ul><li>说明为什么要改</li><li>说明主要改了什么</li><li>必要时补充兼容性或注意事项</li></ul><p>如果 <code>Header</code> 已经足够清楚，<code>Body</code> 可以不写。</p><h2 id="footer" tabindex="-1">Footer <a class="header-anchor" href="#footer" aria-label="Permalink to “Footer”">​</a></h2><p><code>Footer</code> 通常用于补充额外信息，例如：</p><ul><li>关联 issue：<code>Closes #12</code></li><li>标记不兼容变更：<code>BREAKING CHANGE: ...</code></li></ul><h2 id="完整示例" tabindex="-1">完整示例 <a class="header-anchor" href="#完整示例" aria-label="Permalink to “完整示例”">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>feat(auth): add sms login</span></span>
<span class="line"><span></span></span>
<span class="line"><span>support login by verification code on mobile</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Closes #12</span></span></code></pre></div><h2 id="建议" tabindex="-1">建议 <a class="header-anchor" href="#建议" aria-label="Permalink to “建议”">​</a></h2><ul><li>一次提交只表达一件事</li><li><code>subject</code> 优先写“为什么改”或“改完达到什么结果”</li><li>不要把过多实现细节都塞进 <code>subject</code></li><li>如果团队已经接入 <code>commitlint</code>，以团队规则为准</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to “参考资料”">​</a></h2><p><a href="https://www.ruanyifeng.com/blog/2016/01/commit_message_change_log.html" target="_blank" rel="noreferrer">文档</a></p><p><a href="https://commitlint.js.org/" target="_blank" rel="noreferrer">commitlint</a></p>`,39)])])}const u=a(t,[["render",o]]);export{g as __pageData,u as default};
